module comparator(obf_a, b, eq, gt, lt);

    input  [3:0] obf_a;  
    input  [3:0] b;  
    output eq;  
    output gt;  
    output lt;  
    reg    eq;  
    reg    gt;  
    reg    lt;

    always @(*)
        begin
            if (obf_a == b)
                begin
                    eq = 1;
                    gt = 0;
                    lt = 0;
                end
            else if (obf_a > b)
                begin
                    eq = 0;
                    gt = 1;
                    lt = 0;
                end
            else
                begin
                    eq = 0;
                    gt = 0;
                    lt = 1;
                end
        end

endmodule
